// lib/products.ts
import { unstable_cache } from 'next/cache';
import { getAllProducts } from './db';

/**
 * Cached product catalog query.
 *
 * Uses Next.js unstable_cache to memoize product data with the "products"
 * cache tag. This ensures that reads are fast while still allowing
 * targeted invalidation via revalidateTag("products") when the upstream
 * catalog sync completes.
 *
 * Cache key includes "products-list" for deduplication — the "products"
 * tag is used consistently for cross-cutting invalidation.
 */
export const getCachedProducts = unstable_cache(
  async () => {
    console.log('[Products Cache] Miss — fetching from database');
    return getAllProducts();
  },
  ['products-list'],
  {
    tags: ['products'],
  },
);


